import{_ as t}from"./chunks/moveit.QkHgRnlp.js";import{_ as e,c as n,o,a4 as a}from"./chunks/framework.BxjRYGQi.js";const u=JSON.parse('{"title":"Robot Motion Planning with MoveIt2","description":"","frontmatter":{},"headers":[],"relativePath":"en/02-quick-start/03-Moveit2_Simulation.md","filePath":"en/02-quick-start/03-Moveit2_Simulation.md"}'),s={name:"en/02-quick-start/03-Moveit2_Simulation.md"};function r(l,i,h,p,g,d){return o(),n("div",{"data-pagefind-body":!0},i[0]||(i[0]=[a('<h1 id="robot-motion-planning-with-moveit2" tabindex="-1">Robot Motion Planning with MoveIt2 <a class="header-anchor" href="#robot-motion-planning-with-moveit2" aria-label="Permalink to “Robot Motion Planning with MoveIt2”">​</a></h1><p>This section describes how to use MoveIt 2 for motion planning of Agilebot robots. MoveIt 2 is a ROS 2–based robot motion planning framework that integrates the following core features:</p><ul><li><strong>Collision Detection</strong>: Avoids collisions with the environment and the robot itself in real time during planning</li><li><strong>Kinematics Solvers</strong>: Provides efficient forward and inverse kinematics solvers</li><li><strong>Path Planning</strong>: Supports various planar and spatial planning algorithms (e.g., OMPL, CHOMP, STOMP)</li><li><strong>Trajectory Optimization</strong>: Smooths generated paths and enforces velocity/acceleration limits</li><li><strong>Trajectory Execution</strong>: Seamlessly interfaces with hardware controllers for real-time motion control</li><li><strong>Real-Time Replanning</strong>: Automatically updates plans when the environment or goal changes</li><li><strong>Visualization &amp; Debugging</strong>: Displays the planning pipeline in RViz plugins and supports interactive goal setting and parameter tuning</li></ul><p>With MoveIt 2, you can rapidly generate and execute high-quality arm trajectories in both simulation and on real robots, streamlining your development and debugging workflows.</p><figure><img src="'+t+'" alt=""></figure><hr><p>To perform <strong>path planning and motion control</strong> for Shanghai Agilebot Robotics products using MoveIt2, run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {robot_model}_moveit_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.launch.py</span></span></code></pre></div><p>For example, to launch MoveIt2 for the C5A model:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> c5a_moveit_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.launch.py</span></span></code></pre></div><p>This will start the MoveIt2 demonstration interface, enabling path planning and other operations.</p><blockquote><p><strong>Currently only C5A model is supported</strong> for MoveIt2 configuration. Support for MoveIt2 configurations for other models is under development. Users may also configure them manually following the <a href="https://moveit.picknik.ai/main/doc/examples/setup_assistant/setup_assistant_tutorial.html#step-1-start" target="_blank" rel="noreferrer">MoveIt2 official documentation</a>.</p></blockquote>',12)]))}const k=e(s,[["render",r]]);export{u as __pageData,k as default};
